final:
module register (
    input clk,
    input clear,
    input load,
    input [7:0] parallel_in,
    output reg [7:0] Q
);

  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge dbg_halt) begin
    if (clear)
        Q <= 8'b0;
    else if (load)
        Q <= parallel_in;
end

endmodule
